						const icon =
							e.type.includes("pass") || e.type.includes("complete")
								? theme.fg("success", "✓")
								: e.type.includes("fail") ||
										e.type.includes("crash") ||
										e.type.includes("error")
									? theme.fg("error", "✗")
									: e.type.includes("start")
										? theme.fg("accent", "●")
										: e.type === "skip_phase"
											? theme.fg("warning", "⏸")
											: theme.fg("dim", "·");
						const evShort = e.type
							.replace("phase_", "")
							.replace("pipeline_", "")
							.slice(0, 18);
						c.addChild(
							new Text(
								`  ${icon} ${theme.fg("dim", time)} ${theme.fg("muted", evShort)}`,
								0,
								0,
							),
						);
					}
