		if (pkgName) {
			spawnAsync("npm", ["view", pkgName, "version"], {
				cwd: BAKE_BASE,
				timeout: 3000,
			}).then((result) => {
				const latest = (result.stdout || "").trim();
				if (latest) lines.push(`npm latest: ${latest}`);
			}).catch(() => {
				/* npm view failed — non-blocking, silently handled */
			});
		}
	} catch {
		/* package.json not found */
	}

	return lines;
